SELECT date, location_id, hour, da_demd, demand, da_lmp, da_ec, da_cc, da_mlc, rt_lmp, rt_ec, rt_cc, rt_mlc, forecast_accuracy, energy_type, grid_status
FROM energy_data
WHERE location_id = 1 AND date = '1' AND hour = 1;

SELECT AVG(demand) 
FROM energy_data 
WHERE date = '2022-12-01' AND location_id = 1;

SELECT date, AVG(da_demd) AS average_da_demd, AVG(demand) AS average_demand
FROM energy_data
GROUP BY date;

SELECT date, location_id, dry_bulb, humidity, wind_speed, cloud_cover, atmospheric_pressure
FROM weather_data
WHERE location_id = 0 AND date = '0' AND hour = 0 AND dry_bulb > 25;

SELECT AVG(forecast_demand)
FROM energy_demand_forecast
WHERE date = '2022-12-31' AND location_id = 1;
